}


def atomic_write_text(path: Path, content: str, *, encoding: str = "utf-8") -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with tempfile.NamedTemporaryFile("w", encoding=encoding, dir=str(path.parent), delete=False) as handle:
        handle.write(content)
        tmp_path = Path(handle.name)
    os.replace(tmp_path, path)


def atomic_write_json(path: Path, payload: Any) -> None:
    atomic_write_text(path, json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def load_json(path: Path | None) -> dict[str, Any]:
    if path is None or not path.exists():
        return {}
    return json.loads(path.read_text(encoding="utf-8"))


def latest_file(pattern: str) -> Path | None:
    files = sorted(REPORT_DIR.glob(pattern), key=lambda p: p.stat().st_mtime)
    return files[-1] if files else None


def resolve_latest_json(path: Path, pattern: str) -> Path | None:
    if path.exists():
        return path
    return latest_file(pattern)


def normalize_status(value: Any) -> str:
    text = str(value or "").strip().upper()
    if text in {"PASS", "GREEN", "OK"}:
        return "GREEN"
    if text in {"FAIL", "RED", "BLOCK"}:
        return "BLOCK"
    if text in {"YELLOW", "WARN", "WARNING", "PARTIAL"}:
        return "YELLOW"
    return text or "UNKNOWN"


def normalize_date_tag(value: Any) -> str:
    text = str(value or "").strip()
    if re.fullmatch(r"\d{8}", text):
        return text
    m = re.search(r"(20\d{2})[-_/]?(\d{2})[-_/]?(\d{2})", text)
    if m:
        return f"{m.group(1)}{m.group(2)}{m.group(3)}"
    return ""


def guess_trade_date_tag(today_report: dict[str, Any], control_tower: dict[str, Any], daily_audit: dict[str, Any], remediation: dict[str, Any]) -> str:
    return (
        normalize_date_tag(today_report.get("date_tag"))
        or normalize_date_tag(((control_tower.get("strategy_layer") or {}).get("expected_trade_date_tag")))
        or normalize_date_tag(daily_audit.get("date_tag"))
        or normalize_date_tag(remediation.get("report_date"))
        or datetime.now().strftime("%Y%m%d")
    )


def to_trade_date(date_tag: str) -> str:
    if re.fullmatch(r"\d{8}", date_tag):
        return f"{date_tag[:4]}-{date_tag[4:6]}-{date_tag[6:8]}"
    return date_tag


def summarize_profiles(panel: dict[str, Any]) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    rows = panel.get("rows") or []
    main_profiles: list[dict[str, Any]] = []
    breadth_profiles: list[dict[str, Any]] = []
    for row in rows:
        slim = {
            "profile_slug": row.get("profile_slug"),
            "profile_name": row.get("profile_name"),
            "date_tag": row.get("date_tag"),
            "status": row.get("status"),
            "tomorrow_mode": row.get("tomorrow_mode"),
            "nav": row.get("nav"),
            "total_return_pct": row.get("total_return_pct"),
            "day_pnl": row.get("day_pnl"),
            "drawdown_pct": row.get("drawdown_pct"),
            "cash": row.get("cash"),
            "market_value": row.get("market_value"),
            "position_count": row.get("position_count"),
            "today_trade_count": row.get("today_trade_count"),
            "issue_codes": row.get("issue_codes"),
        }
        slug = str(row.get("profile_slug") or "")
        if slug.startswith("breadth_"):
            breadth_profiles.append(slim)
        else:
            main_profiles.append(slim)
    return main_profiles, breadth_profiles


def build_acceptance_watchlist(remediation: dict[str, Any], role_output_archive: dict[str, Any]) -> list[dict[str, Any]]:
    items = remediation.get("items") or {}
    evidence = remediation.get("evidence") or {}
    watchlist: list[dict[str, Any]] = []
    for key in remediation.get("next_priority") or []:
        status = str(items.get(key) or "").strip().lower()
        if status not in {"partial", "block", "blocked"}:
            continue
        entry = {
            "key": key,
            "status": status,
            "summary": ACCEPTANCE_LABELS.get(key, key),
            "evidence": evidence.get(
                {
                    "P0-3_manual_intervention_audit": "p0_3_progress_report",
                    "P2-1_data_snapshot_and_versioning": "p2_1_progress_report",
                    "P2-3_role_outputs_archival": "p2_3_progress_report",
                }.get(key, ""),
                "",
            ),
        }
        if key == "P2-3_role_outputs_archival":
            coverage = {}
            for role in role_output_archive.get("roles") or []:
                coverage[str(role.get("role") or "")] = {
                    "covered_week_count": role.get("covered_week_count"),
                    "meets_4week_requirement": role.get("meets_4week_requirement"),
                }
            entry["coverage"] = coverage
        watchlist.append(entry)
    return watchlist


