    elif label == "manual_review_closure_alert":
        candidates = [payload.get("date_tag"), payload.get("report_date")]
    elif label == "role_output_archive":
        candidates = [payload.get("date_tag"), payload.get("report_date")]
    return next((normalize_date_tag(item) for item in candidates if normalize_date_tag(item)), "")


def file_entry(label: str, path: Path | None, payload: dict[str, Any], *, required: bool, trade_date_tag: str) -> dict[str, Any]:
    if path is None:
        return {
            "label": label,
            "required": required,
            "exists": False,
